CREATE OR REPLACE FUNCTION fpb_fin_get_bf_fw_entry (as_branch CHAR ,adtm_date timestamp(0), as_type CHAR , as_entry char ) RETURNS bigint AS $body$
DECLARE

ldc_begin bigint;
ldc_forward bigint;
ldc_rec bigint;
ldc_pay bigint;


BEGIN
    select  sum( sc_fin_journal_head.balance_begin) ,
            sum( sc_fin_journal_head.balance_forward ) ,
            sum( sc_fin_journal_head.total_receive ) ,
            sum( sc_fin_journal_head.total_payment )
    INTO STRICT    ldc_begin, ldc_forward, ldc_rec, ldc_pay
    FROM    sc_fin_journal_head
    WHERE ( sc_fin_journal_head.branch_fin = as_branch ) and ( sc_fin_journal_head.journal_date = adtm_date ) and ( sc_fin_journal_head.entry_fin = as_entry );

    case trim(both upper( as_type ))
    when 'BF' then
      if coalesce(ldc_begin::text, '') = '' then ldc_begin := 0;end if;
      return ldc_begin;
    when 'FW' then
      if coalesce(ldc_forward::text, '') = '' then ldc_forward := 0;end if;
      return ldc_forward;
    when 'REC' then
      if coalesce(ldc_rec::text, '') = '' then ldc_rec := 0;end if;
      return ldc_rec;
    when 'PAY' then
      if coalesce(ldc_pay::text, '') = '' then ldc_pay := 0;end if;
      return ldc_pay;
    else
      return 0;
    end case;

END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
